package arch.day51;

/**
 * Prints simple reference tables. No Spring needed.
 * Spring idea: // split code into modules per business area + test imports with ArchUnit
 */
public class Day51Basic {

    public static void main(String[] args) {
        System.out.println("=== When separate services often make sense ===");
        System.out.println("Situation                         | Plain explanation");
        System.out.println("Read-heavy search vs writes       | Scale or deploy search differently");
        System.out.println("Different release schedules       | One team ships often, one ships rarely");
        System.out.println("Compliance / card data            | Isolate sensitive parts");
        System.out.println("Many teams, clear ownership       | Matches who maintains what");
        System.out.println();

        System.out.println("=== When one well-structured app is often better ===");
        System.out.println("Situation                         | Plain explanation");
        System.out.println("Small team, early product         | Extra services add ops work");
        System.out.println("Boundaries still unclear          | Draw lines before splitting");
        System.out.println("Heavy shared rules across areas   | Model first, then split data");
        System.out.println("Low traffic internal tool         | Network calls add little value");
        System.out.println();

        System.out.println("=== DDD building blocks (simple meanings) ===");
        System.out.println("Block              | Plain meaning");
        System.out.println("Entity             | Thing with identity that can change over time");
        System.out.println("Value object       | Small immutable piece (e.g. money with currency)");
        System.out.println("Aggregate root     | The one door to change a cluster safely");
        System.out.println("Domain event       | Something that already happened (past tense)");
        System.out.println("Repository         | Load/save aggregates; hides the database");
        System.out.println("Domain service     | Rule that does not fit one entity");
        System.out.println("Factory            | Creates a new aggregate with valid start state");
        System.out.println("ACL                | Translator for external or legacy data shapes");
        System.out.println();

        System.out.println("=== How areas relate (names interviewers like) ===");
        System.out.println("Partnership        | Two teams share and evolve one model");
        System.out.println("Customer-Supplier  | Downstream asks upstream for roadmap help");
        System.out.println("Conformist         | Downstream copies upstream model as-is");
        System.out.println("Anti-corruption    | Downstream translates foreign model");
        System.out.println("Open Host          | Upstream publishes a clear integration API");
        System.out.println("Published Language | Shared stable format between areas");
    }
}

package arch.day51;

import java.util.*;

/**
 * Small simulation: order as aggregate root, inventory as a "port,"
 * a list of domain events, and duplicate message handling.
 * Spring mapping (comments only):
 * // @Transactional service calls InventoryClient implementing InventoryPort
 * // Save outbox rows in same DB transaction as order save
 */
public class Day51Intermediate {

    static final List<String> domainEvents = new ArrayList<>();

    static final class Line {
        final String sku;
        final int qty;
        Line(String sku, int qty) {
            this.sku = sku;
            this.qty = qty;
        }
    }

    static final class OrderAggregate {
        private final String id;
        private final List<Line> lines = new ArrayList<>();
        private String status = "DRAFT";

        OrderAggregate(String id) {
            this.id = id;
        }

        void addLine(String sku, int qty) {
            if (sku == null || sku.isBlank()) {
                throw new IllegalArgumentException("sku required");
            }
            if (qty <= 0) {
                throw new IllegalArgumentException("qty must be positive");
            }
            lines.add(new Line(sku, qty));
        }

        void submit(InventoryPort inventory) {
            if (lines.isEmpty()) {
                throw new IllegalStateException("cannot submit empty order");
            }
            for (Line line : lines) {
                if (!inventory.tryReserve(line.sku, line.qty)) {
                    throw new IllegalStateException("insufficient stock: " + line.sku);
                }
            }
            status = "SUBMITTED";
            domainEvents.add("OrderSubmitted:" + id);
            for (Line line : lines) {
                domainEvents.add("InventoryReserved:" + line.sku + ":" + line.qty);
            }
        }

        String status() {
            return status;
        }
    }

    interface InventoryPort {
        boolean tryReserve(String sku, int qty);
    }

    static final class FakeWarehouse implements InventoryPort {
        private final Map<String, Integer> stock = new HashMap<>();

        FakeWarehouse() {
            stock.put("SKU-A", 10);
            stock.put("SKU-B", 1);
        }

        @Override
        public boolean tryReserve(String sku, int qty) {
            int available = stock.getOrDefault(sku, 0);
            if (available < qty) {
                return false;
            }
            stock.put(sku, available - qty);
            return true;
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Order context simulation (aggregate + port) ===\n");

        // --- Scenario 1: happy path ---
        System.out.println("--- Scenario 1: happy path ---");
        domainEvents.clear();
        FakeWarehouse wh1 = new FakeWarehouse();
        OrderAggregate o1 = new OrderAggregate("ord-7001");
        o1.addLine("SKU-A", 2);
        o1.submit(wh1);
        System.out.println("status=" + o1.status() + " events=" + domainEvents.size());
        System.out.println();

        // --- Scenario 2: retry / replay (at-least-once consumer) ---
        System.out.println("--- Scenario 2: idempotent consumer replay ---");
        List<String> seen = new ArrayList<>();
        String dedup = "evt-order-7001";
        Runnable handle = () -> {
            if (!seen.contains(dedup)) {
                seen.add(dedup);
                System.out.println("processed " + dedup);
            } else {
                System.out.println("skipped duplicate " + dedup);
            }
        };
        handle.run();
        handle.run();
        System.out.println();

        // --- Scenario 3: failure / edge (stock breaks invariant) ---
        System.out.println("--- Scenario 3: failure — insufficient stock ---");
        domainEvents.clear();
        FakeWarehouse wh2 = new FakeWarehouse();
        OrderAggregate o2 = new OrderAggregate("ord-7002");
        o2.addLine("SKU-B", 5);
        try {
            o2.submit(wh2);
            System.out.println("unexpected success");
        } catch (IllegalStateException ex) {
            System.out.println("rejected: " + ex.getMessage());
            System.out.println("status=" + o2.status() + " events=" + domainEvents.size());
        }
        System.out.println();

        // --- Scenario 4: summary rules ---
        System.out.println("--- Scenario 4: summary rules ---");
        System.out.println("Rule 1: modify one aggregate per transaction when possible");
        System.out.println("Rule 2: cross-context integration uses ports, not foreign entities");
        System.out.println("Rule 3: domain events are past-tense facts after state change");
        System.out.println("Rule 4: consumers must be idempotent under at-least-once delivery");
    }
}

package arch.day51;

import java.util.*;

/**
 * Records + a small scoring formula + printed tables.
 * Not a real decision engine — a learning aid only.
 * Spring note:
 * // Split services when teams and SLOs truly differ; keep a modular app until then
 */
public class Day51Advanced {

    record ServiceBoundaryCandidate(
            String name,
            int teamAutonomy0to10,
            int dataCohesion0to10,
            int changeCoupling0to10,
            int slaConflict0to10) {
    }

    record ContextLink(String upstream, String downstream, String relationship) {
    }

    static int boundaryScore(ServiceBoundaryCandidate c) {
        return c.teamAutonomy0to10() * 2
                + c.dataCohesion0to10() * 3
                - c.changeCoupling0to10() * 2
                - c.slaConflict0to10() * 2;
    }

    static void printScores(List<ServiceBoundaryCandidate> candidates) {
        List<ServiceBoundaryCandidate> sorted = new ArrayList<>(candidates);
        sorted.sort(Comparator.comparingInt(Day51Advanced::boundaryScore).reversed());
        for (ServiceBoundaryCandidate c : sorted) {
            System.out.println(c.name() + " score=" + boundaryScore(c));
        }
    }

    public static void main(String[] args) {

        // === Block 1: candidate scoring ===
        System.out.println("=== Block 1: boundary candidate scores ===");
        System.out.println("Formula: +2*autonomy +3*cohesion -2*coupling -2*slaConflict");
        System.out.println();
        List<ServiceBoundaryCandidate> candidates = List.of(
                new ServiceBoundaryCandidate("billing", 8, 9, 3, 2),
                new ServiceBoundaryCandidate("catalog", 7, 8, 4, 1),
                new ServiceBoundaryCandidate("search-read", 6, 5, 8, 6)
        );
        printScores(candidates);
        System.out.println();

        // === Block 2: context map links ===
        System.out.println("=== Block 2: example context map links ===");
        List<ContextLink> links = List.of(
                new ContextLink("pricing", "orders", "Customer-Supplier + PublishedLanguage"),
                new ContextLink("legacy-crm", "subscriptions", "Anti-corruption Layer"),
                new ContextLink("identity", "all", "Open Host Service (OIDC claims)")
        );
        for (ContextLink l : links) {
            System.out.println(l.upstream() + " -> " + l.downstream() + " : " + l.relationship());
        }
        System.out.println();

        // === Block 3: decision reference table ===
        System.out.println("=== Block 3: decomposition decision reference ===");
        System.out.println("Symptom                              | Likely move");
        System.out.println("Shared DB + cross-team migrations    | Split data + events/API");
        System.out.println("Chatty sync chain p95 high             | Consolidate or async + saga");
        System.out.println("Different RPS on read vs write         | CQRS projection service");
        System.out.println("Team communication bottleneck          | Align Conway + contexts");
        System.out.println("Duplicate business rules in 2 services | Upstream published language");
        System.out.println("Unknown vocabulary drift               | Event storming + glossary");
        System.out.println("Legacy model leaking in               | ACL + translation DTOs");
        System.out.println("Duplicate side effects on retry        | Idempotency + outbox");
        System.out.println("Heavy join queries pre-split           | Read model + CDC/events");
        System.out.println("One team owns all                      | Modular monolith first");
    }
}

