package arch.day51;

import java.util.*;

/**
 * Small runnable sketch: order aggregate, two "ports," payment dedup.
 * Comments use plain language on purpose.
 */
public class Day51Exercise {

    interface InventoryPort {
        boolean reserve(String sku, int qty);
    }

    interface PaymentGatewayPort {
        String capture(String orderId, int amountMinor);
    }

    static final class StubInventory implements InventoryPort {
        public boolean reserve(String sku, int qty) {
            return qty > 0 && sku.startsWith("SKU-");
        }
    }

    static final class StubPay implements PaymentGatewayPort {
        public String capture(String orderId, int amountMinor) {
            return "pay-" + orderId + "-" + amountMinor;
        }
    }

    static final class OrderAggregate {
        private final String id;
        private final List<String> lines = new ArrayList<>();
        private String status = "DRAFT";
        private int totalMinor = 0;

        OrderAggregate(String id) {
            this.id = id;
        }

        void addLine(String sku, int qty, int unitMinor) {
            if (qty <= 0 || unitMinor <= 0) {
                throw new IllegalArgumentException("invalid line");
            }
            lines.add(sku + "x" + qty);
            totalMinor += qty * unitMinor;
        }

        void submit(InventoryPort inventory) {
            if (lines.isEmpty()) {
                throw new IllegalStateException("empty");
            }
            if (!inventory.reserve("SKU-DEMO", 1)) {
                throw new IllegalStateException("inventory unavailable");
            }
            status = "SUBMITTED";
        }

        String pay(PaymentGatewayPort pay) {
            if (!"SUBMITTED".equals(status)) {
                throw new IllegalStateException("wrong state");
            }
            String ref = pay.capture(id, totalMinor);
            status = "PAID";
            return ref;
        }

        String status() {
            return status;
        }
    }

    // In production: store keys in DB with a unique index — not only in memory.
    static String handlePaymentCaptured(String dedupKey,
                                        String orderId,
                                        Set<String> processedKeys) {
        if (processedKeys.contains(dedupKey)) {
            return "DUPLICATE_IGNORED";
        }
        processedKeys.add(dedupKey);
        return "LEDGER_UPDATED:" + orderId;
    }

    public static void main(String[] args) {
        StubInventory inv = new StubInventory();
        StubPay pay = new StubPay();
        OrderAggregate order = new OrderAggregate("ord-ex-1");
        order.addLine("SKU-DEMO", 1, 500);
        order.submit(inv);
        String ref = order.pay(pay);
        System.out.println("orderStatus=" + order.status() + " paymentRef=" + ref);

        Set<String> keys = new HashSet<>();
        String businessDedup = "ord-ex-1:capture";
        System.out.println(handlePaymentCaptured(businessDedup, "ord-ex-1", keys));
        System.out.println(handlePaymentCaptured(businessDedup, "ord-ex-1", keys));

        System.out.println("metric: saga_stage_latency_ms{stage=CAPTURE} p99 + DLQ depth");
    }
}

